UPDATE public.questions SET
  stimulus_text = 'The study, which was conducted by a team of researchers from the University of California, Berkeley, found that people who are regularly exposed to nature are more likely to be happier and healthier. The researchers suggested that spending time in nature can help reduce stress, improve concentration, and boost creativity. Taken together, these details imply a broader principle that extends beyond the immediate example, though the author stops short of claiming universal proof. Readers must weigh both the evidence presented and the limits the author acknowledges.',
